//! Microbench: matmul_batched_nt vs the existing per-token matVec loop
//! that mat_vec_f32_batch implements under the hood.
//!
//! Shapes:
//!   * 384 × 384  (whisper-tiny  hidden) ×  2000 iters
//!   * 512 × 512  (whisper-base  hidden) ×  1000 iters
//!
//! Reports wall time, GFLOPs, and speedup vs the matVec-equivalent loop
//! built from the existing `math::dot_product` kernel (so the comparison is
//! against the SAME NEON dot we'd be replacing — not a strawman scalar).

use distributed_inference::math::dot_product;
use distributed_inference::math_batched::matmul_batched_nt;
use std::time::Instant;

/// The "old way": for each token row of A, dot against every B row.
/// Equivalent to `mat_vec_f32_batch` minus the rayon overhead — we benchmark
/// single-threaded so we measure SIMD/cache wins, not parallelism.
#[inline(never)]
fn matvec_loop_baseline(a: &[f32], b: &[f32], c: &mut [f32], m: usize, n: usize, k: usize) {
    for t in 0..m {
        let a_row = &a[t * k..(t + 1) * k];
        for i in 0..n {
            let b_row = &b[i * k..(i + 1) * k];
            c[t * n + i] = dot_product(a_row, b_row);
        }
    }
}

fn run_case(name: &str, m: usize, n: usize, k: usize, iters: usize) {
    let a: Vec<f32> = (0..m * k).map(|i| (i as f32 * 0.001).sin()).collect();
    let b: Vec<f32> = (0..n * k).map(|i| (i as f32 * 0.0007).cos()).collect();
    let mut c_old = vec![0.0f32; m * n];
    let mut c_new = vec![0.0f32; m * n];

    // ── Correctness sanity (m × n cells, abs diff vs each other) ───────────
    matvec_loop_baseline(&a, &b, &mut c_old, m, n, k);
    matmul_batched_nt(&a, &b, &mut c_new, m, n, k);
    let max_diff = c_old
        .iter()
        .zip(c_new.iter())
        .map(|(x, y)| (x - y).abs())
        .fold(0.0f32, f32::max);
    let max_mag = c_old.iter().map(|v| v.abs()).fold(0.0f32, f32::max);
    eprintln!(
        "[{}] correctness: max abs diff = {:.3e} (max |C| = {:.3e}, rel = {:.3e})",
        name,
        max_diff,
        max_mag,
        max_diff / max_mag.max(1e-30)
    );

    // ── Warmup ─────────────────────────────────────────────────────────────
    for _ in 0..5 {
        matvec_loop_baseline(&a, &b, &mut c_old, m, n, k);
        matmul_batched_nt(&a, &b, &mut c_new, m, n, k);
    }

    // ── Baseline (matVec loop) ─────────────────────────────────────────────
    let t0 = Instant::now();
    for _ in 0..iters {
        matvec_loop_baseline(&a, &b, &mut c_old, m, n, k);
    }
    let elapsed_old = t0.elapsed();
    let per_old_us = elapsed_old.as_secs_f64() * 1e6 / iters as f64;

    // ── New batched kernel ─────────────────────────────────────────────────
    let t1 = Instant::now();
    for _ in 0..iters {
        matmul_batched_nt(&a, &b, &mut c_new, m, n, k);
    }
    let elapsed_new = t1.elapsed();
    let per_new_us = elapsed_new.as_secs_f64() * 1e6 / iters as f64;

    // ── FLOP accounting ────────────────────────────────────────────────────
    // 2 * m * n * k FMAs per matmul.
    let flops = 2.0 * m as f64 * n as f64 * k as f64;
    let gflops_old = flops / (per_old_us * 1e3); // (FLOP / us) * 1e-3 = GFLOP/s
    let gflops_new = flops / (per_new_us * 1e3);
    let speedup = per_old_us / per_new_us;

    println!();
    println!(
        "─── {} (m={}, n={}, k={}, iters={}) ───",
        name, m, n, k, iters
    );
    println!(
        "  matVec-loop  : {:8.1} us/call  ({:6.2} GFLOPs)",
        per_old_us, gflops_old
    );
    println!(
        "  batched NT   : {:8.1} us/call  ({:6.2} GFLOPs)",
        per_new_us, gflops_new
    );
    println!("  SPEEDUP      : {:6.2}×", speedup);
}

fn main() {
    println!("== bench-batched-matmul (single-threaded) ==");
    println!("Comparing matmul_batched_nt vs per-token matVec loop");
    println!("(dot_product is the same NEON kernel mat_vec_f32_batch uses)");

    run_case("whisper-tiny  384", 8, 384, 384, 2000);
    run_case("whisper-base  512", 8, 512, 512, 1000);

    // Also report a "real encoder seq" shape — whisper-base has seq=1500 mel
    // frames after 2× downsample. m=1500, n=512, k=512 measures the actual
    // shape in the encoder hot loop.
    run_case("whisper-base seq=1500", 1500, 512, 512, 50);
    // FFN expansion shape: fc1 is (inter=2048, hidden=512). seq=1500 again.
    run_case("whisper-base fc1 1500x2048x512", 1500, 2048, 512, 25);
}
